<template><PageContainer title="医生排班" desc="按星期几与时段统一管理医生排班"><div class="page-card page-block" style="margin-bottom:18px;"><div class="section-title">新增排班</div><el-form :model="form" label-width="88px"><div class="form-grid"><el-form-item label="医生"><el-select v-model="form.doctorId" placeholder="请选择医生"><el-option v-for="item in doctors" :key="item.id" :label="`${item.name}（${item.departmentName}）`" :value="item.id" /></el-select></el-form-item><el-form-item label="星期"><el-select v-model="form.weekday"><el-option v-for="n in 7" :key="n" :label="weekdayLabel(n)" :value="n" /></el-select></el-form-item><el-form-item label="时段"><el-select v-model="form.period"><el-option label="上午" value="上午" /><el-option label="下午" value="下午" /><el-option label="夜间" value="夜间" /></el-select></el-form-item><el-form-item label="最大号源"><el-input-number v-model="form.maxNumber" :min="1" :max="100" /></el-form-item><el-form-item label="挂号费用"><el-input-number v-model="form.fee" :min="1" :max="500" /></el-form-item></div><el-form-item><el-button type="primary" @click="submit">新增排班</el-button></el-form-item></el-form></div><el-table :data="list" border><el-table-column prop="departmentName" label="科室" /><el-table-column prop="doctorName" label="医生" /><el-table-column label="星期" width="100"><template #default="{ row }">{{ weekdayLabel(row.weekday) }}</template></el-table-column><el-table-column prop="period" label="时段" width="100" /><el-table-column prop="maxNumber" label="号源" width="90" /><el-table-column prop="fee" label="费用" width="90" /><el-table-column label="状态" width="90"><template #default="{ row }"><span class="status-tag" :class="row.status === 1 ? 'status-success' : 'status-warning'">{{ row.status === 1 ? '正常' : '停用' }}</span></template></el-table-column></el-table></PageContainer></template>
<script setup>
import { onMounted, reactive, ref } from 'vue'; import { adminApi } from '../../api/modules'; import PageContainer from '../../components/PageContainer.vue'; import { successTip, weekdayLabel } from '../../utils'
const list = ref([]); const doctors = ref([]); const form = reactive({ doctorId: '', weekday: 1, period: '上午', maxNumber: 20, fee: 15 })
async function loadAll() { const [scheduleRes, doctorRes] = await Promise.all([adminApi.schedules(), adminApi.doctors()]); list.value = scheduleRes.data; doctors.value = doctorRes.data }
async function submit() { await adminApi.createSchedule(form); successTip('排班新增成功'); loadAll() }
onMounted(loadAll)
</script>
